   166→func NewLeveledCompactorWithChunkSize(ctx context.Context, r prometheus.Registerer, l log.Logger, ranges []int64, pool chunkenc.Pool, maxBlockChunkSegmentSize int64, mergeFunc storage.VerticalChunkSeriesMergeFunc) (*LeveledCompactor, error) {
   167→	return NewLeveledCompactorWithOptions(ctx, r, l, ranges, pool, LeveledCompactorOptions{
   168→		MaxBlockChunkSegmentSize:    maxBlockChunkSegmentSize,
   169→		MergeFunc:                   mergeFunc,
   170→		EnableOverlappingCompaction: true,
   171→	})
   172→}
