   216→type dirMeta struct {
   217→	dir  string
   218→	meta *BlockMeta
   219→}
   220→
   221→// Plan returns a list of compactable blocks in the provided directory.
   222→func (c *LeveledCompactor) Plan(dir string) ([]string, error) {
   223→	dirs, err := blockDirs(dir)
   224→	if err != nil {
   225→		return nil, err
   226→	}
   227→	if len(dirs) < 1 {
   228→		return nil, nil
   229→	}
   230→
   231→	var dms []dirMeta
   232→	for _, dir := range dirs {
   233→		meta, _, err := readMetaFile(dir)
   234→		if err != nil {
   235→			return nil, err
   236→		}
   237→		dms = append(dms, dirMeta{dir, meta})
   238→	}
   239→	return c.plan(dms)
   240→}
   241→
   242→func (c *LeveledCompactor) plan(dms []dirMeta) ([]string, error) {
   243→	slices.SortFunc(dms, func(a, b dirMeta) int {
   244→		switch {
   245→		case a.meta.MinTime < b.meta.MinTime:
   246→			return -1
   247→		case a.meta.MinTime > b.meta.MinTime:
   248→			return 1
   249→		default:
   250→			return 0
   251→		}
   252→	})
   253→
   254→	res := c.selectOverlappingDirs(dms)
   255→	if len(res) > 0 {
   256→		return res, nil
   257→	}
   258→	// No overlapping blocks, do compaction the usual way.
   259→	// We do not include a recently created block with max(minTime), so the block which was just created from WAL.
   260→	// This gives users a window of a full block size to piece-wise backup new data without having to care about data overlap.
   261→	dms = dms[:len(dms)-1]
   262→
   263→	for _, dm := range c.selectDirs(dms) {
   264→		res = append(res, dm.dir)
   265→	}
   266→	if len(res) > 0 {
   267→		return res, nil
   268→	}
   269→
   270→	// Compact any blocks with big enough time range that have >5% tombstones.
   271→	for i := len(dms) - 1; i >= 0; i-- {
   272→		meta := dms[i].meta
   273→		if meta.MaxTime-meta.MinTime < c.ranges[len(c.ranges)/2] {
   274→			// If the block is entirely deleted, then we don't care about the block being big enough.
   275→			// TODO: This is assuming single tombstone is for distinct series, which might be no true.
   276→			if meta.Stats.NumTombstones > 0 && meta.Stats.NumTombstones >= meta.Stats.NumSeries {
   277→				return []string{dms[i].dir}, nil
   278→			}
   279→			break
   280→		}
   281→		if float64(meta.Stats.NumTombstones)/float64(meta.Stats.NumSeries+1) > 0.05 {
   282→			return []string{dms[i].dir}, nil
   283→		}
   284→	}
   285→
   286→	return nil, nil
   287→}
   288→
   289→// selectDirs returns the dir metas that should be compacted into a single new block.
   290→// If only a single block range is configured, the result is always nil.
   291→func (c *LeveledCompactor) selectDirs(ds []dirMeta) []dirMeta {
   292→	if len(c.ranges) < 2 || len(ds) < 1 {
   293→		return nil
   294→	}
   295→
   296→	highTime := ds[len(ds)-1].meta.MinTime
   297→
   298→	for _, iv := range c.ranges[1:] {
   299→		parts := splitByRange(ds, iv)
   300→		if len(parts) == 0 {
   301→			continue
   302→		}
   303→
   304→	Outer:
   305→		for _, p := range parts {
   306→			// Do not select the range if it has a block whose compaction failed.
   307→			for _, dm := range p {
   308→				if dm.meta.Compaction.Failed {
   309→					continue Outer
   310→				}
   311→			}
   312→
   313→			mint := p[0].meta.MinTime
   314→			maxt := p[len(p)-1].meta.MaxTime
   315→			// Pick the range of blocks if it spans the full range (potentially with gaps)
   316→			// or is before the most recent block.
   317→			// This ensures we don't compact blocks prematurely when another one of the same
   318→			// size still fits in the range.
   319→			if (maxt-mint == iv || maxt <= highTime) && len(p) > 1 {
   320→				return p
   321→			}
   322→		}
   323→	}
   324→
   325→	return nil
   326→}
   327→
   328→// selectOverlappingDirs returns all dirs with overlapping time ranges.
   329→// It expects sorted input by mint and returns the overlapping dirs in the same order as received.
   330→func (c *LeveledCompactor) selectOverlappingDirs(ds []dirMeta) []string {
   331→	if !c.enableOverlappingCompaction {
   332→		return nil
   333→	}
   334→	if len(ds) < 2 {
   335→		return nil
   336→	}
   337→	var overlappingDirs []string
   338→	globalMaxt := ds[0].meta.MaxTime
   339→	for i, d := range ds[1:] {
   340→		if d.meta.MinTime < globalMaxt {
   341→			if len(overlappingDirs) == 0 { // When it is the first overlap, need to add the last one as well.
   342→				overlappingDirs = append(overlappingDirs, ds[i].dir)
   343→			}
   344→			overlappingDirs = append(overlappingDirs, d.dir)
   345→		} else if len(overlappingDirs) > 0 {
   346→			break
   347→		}
   348→		if d.meta.MaxTime > globalMaxt {
   349→			globalMaxt = d.meta.MaxTime
   350→		}
   351→	}
   352→	return overlappingDirs
   353→}
   354→
   355→// splitByRange splits the directories by the time range. The range sequence starts at 0.
   356→//
   357→// For example, if we have blocks [0-10, 10-20, 50-60, 90-100] and the split range tr is 30
   358→// it returns [0-10, 10-20], [50-60], [90-100].
   359→func splitByRange(ds []dirMeta, tr int64) [][]dirMeta {
   360→	var splitDirs [][]dirMeta
   361→
   362→	for i := 0; i < len(ds); {
   363→		var (
   364→			group []dirMeta
   365→			t0    int64
   366→			m     = ds[i].meta
   367→		)
   368→		// Compute start of aligned time range of size tr closest to the current block's start.
   369→		if m.MinTime >= 0 {
   370→			t0 = tr * (m.MinTime / tr)
   371→		} else {
   372→			t0 = tr * ((m.MinTime - tr + 1) / tr)
   373→		}
   374→		// Skip blocks that don't fall into the range. This can happen via mis-alignment or
   375→		// by being the multiple of the intended range.
   376→		if m.MaxTime > t0+tr {
   377→			i++
   378→			continue
   379→		}
   380→
   381→		// Add all dirs to the current group that are within [t0, t0+tr].
   382→		for ; i < len(ds); i++ {
   383→			// Either the block falls into the next range or doesn't fit at all (checked above).
   384→			if ds[i].meta.MaxTime > t0+tr {
   385→				break
   386→			}
   387→			group = append(group, ds[i])
   388→		}
   389→
   390→		if len(group) > 0 {
   391→			splitDirs = append(splitDirs, group)
   392→		}
   393→	}
   394→
   395→	return splitDirs
   396→}
   397→
   398→// CompactBlockMetas merges many block metas into one, combining it's source blocks together
   399→// and adjusting compaction level. Min/Max time of result block meta covers all input blocks.
   400→func CompactBlockMetas(uid ulid.ULID, blocks ...*BlockMeta) *BlockMeta {
   401→	res := &BlockMeta{
   402→		ULID: uid,
   403→	}
   404→
   405→	sources := map[ulid.ULID]struct{}{}
   406→	mint := blocks[0].MinTime
   407→	maxt := blocks[0].MaxTime
   408→
   409→	for _, b := range blocks {
   410→		if b.MinTime < mint {
   411→			mint = b.MinTime
   412→		}
   413→		if b.MaxTime > maxt {
   414→			maxt = b.MaxTime
   415→		}
   416→		if b.Compaction.Level > res.Compaction.Level {
   417→			res.Compaction.Level = b.Compaction.Level
   418→		}
   419→		for _, s := range b.Compaction.Sources {
   420→			sources[s] = struct{}{}
   421→		}
   422→		res.Compaction.Parents = append(res.Compaction.Parents, BlockDesc{
   423→			ULID:    b.ULID,
   424→			MinTime: b.MinTime,
   425→			MaxTime: b.MaxTime,
   426→		})
   427→	}
   428→	res.Compaction.Level++
   429→
   430→	for s := range sources {
   431→		res.Compaction.Sources = append(res.Compaction.Sources, s)
   432→	}
   433→	slices.SortFunc(res.Compaction.Sources, func(a, b ulid.ULID) int {
   434→		return a.Compare(b)
   435→	})
   436→
   437→	res.MinTime = mint
   438→	res.MaxTime = maxt
   439→	return res
   440→}
   441→
   442→// Compact creates a new block in the compactor's directory from the blocks in the
   443→// provided directories.
   444→func (c *LeveledCompactor) Compact(dest string, dirs []string, open []*Block) (uid ulid.ULID, err error) {
   445→	return c.CompactWithBlockPopulator(dest, dirs, open, DefaultBlockPopulator{})
   446→}
   447→
   448→func (c *LeveledCompactor) CompactWithBlockPopulator(dest string, dirs []string, open []*Block, blockPopulator BlockPopulator) (uid ulid.ULID, err error) {
   449→	var (
   450→		blocks []BlockReader
   451→		bs     []*Block
   452→		metas  []*BlockMeta
   453→		uids   []string
   454→	)
   455→	start := time.Now()
   456→
   457→	for _, d := range dirs {
   458→		meta, _, err := readMetaFile(d)
   459→		if err != nil {
   460→			return uid, err
   461→		}
   462→
   463→		var b *Block
   464→
   465→		// Use already open blocks if we can, to avoid
   466→		// having the index data in memory twice.
   467→		for _, o := range open {
   468→			if meta.ULID == o.Meta().ULID {
   469→				b = o
   470→				break
   471→			}
   472→		}
   473→
   474→		if b == nil {
   475→			var err error
   476→			b, err = OpenBlock(c.logger, d, c.chunkPool)
   477→			if err != nil {
   478→				return uid, err
   479→			}
   480→			defer b.Close()
   481→		}
   482→
   483→		metas = append(metas, meta)
   484→		blocks = append(blocks, b)
   485→		bs = append(bs, b)
   486→		uids = append(uids, meta.ULID.String())
   487→	}
   488→
   489→	uid = ulid.MustNew(ulid.Now(), rand.Reader)
   490→
   491→	meta := CompactBlockMetas(uid, metas...)
   492→	err = c.write(dest, meta, blockPopulator, blocks...)
   493→	if err == nil {
   494→		if meta.Stats.NumSamples == 0 {
   495→			for _, b := range bs {
   496→				b.meta.Compaction.Deletable = true
   497→				n, err := writeMetaFile(c.logger, b.dir, &b.meta)
   498→				if err != nil {
   499→					level.Error(c.logger).Log(
   500→						"msg", "Failed to write 'Deletable' to meta file after compaction",
   501→						"ulid", b.meta.ULID,
   502→					)
   503→				}
   504→				b.numBytesMeta = n
   505→			}
   506→			uid = ulid.ULID{}
   507→			level.Info(c.logger).Log(
   508→				"msg", "compact blocks resulted in empty block",
   509→				"count", len(blocks),
   510→				"sources", fmt.Sprintf("%v", uids),
   511→				"duration", time.Since(start),
   512→			)
   513→		} else {
   514→			level.Info(c.logger).Log(
   515→				"msg", "compact blocks",
   516→				"count", len(blocks),
   517→				"mint", meta.MinTime,
   518→				"maxt", meta.MaxTime,
   519→				"ulid", meta.ULID,
   520→				"sources", fmt.Sprintf("%v", uids),
   521→				"duration", time.Since(start),
   522→			)
   523→		}
   524→		return uid, nil
   525→	}
   526→
   527→	errs := tsdb_errors.NewMulti(err)
   528→	if !errors.Is(err, context.Canceled) {
   529→		for _, b := range bs {
   530→			if err := b.setCompactionFailed(); err != nil {
   531→				errs.Add(fmt.Errorf("setting compaction failed for block: %s: %w", b.Dir(), err))
   532→			}
   533→		}
   534→	}
   535→
   536→	return uid, errs.Err()
   537→}
   538→
   539→func (c *LeveledCompactor) Write(dest string, b BlockReader, mint, maxt int64, base *BlockMeta) (ulid.ULID, error) {
   540→	start := time.Now()
   541→
   542→	uid := ulid.MustNew(ulid.Now(), rand.Reader)
   543→
   544→	meta := &BlockMeta{
   545→		ULID:    uid,
   546→		MinTime: mint,
   547→		MaxTime: maxt,
   548→	}
   549→	meta.Compaction.Level = 1
   550→	meta.Compaction.Sources = []ulid.ULID{uid}
   551→
   552→	if base != nil {
   553→		meta.Compaction.Parents = []BlockDesc{
   554→			{ULID: base.ULID, MinTime: base.MinTime, MaxTime: base.MaxTime},
   555→		}
   556→		if base.Compaction.FromOutOfOrder() {
   557→			meta.Compaction.SetOutOfOrder()
   558→		}
   559→	}
   560→
   561→	err := c.write(dest, meta, DefaultBlockPopulator{}, b)
   562→	if err != nil {
   563→		return uid, err
   564→	}
   565→
   566→	if meta.Stats.NumSamples == 0 {
   567→		level.Info(c.logger).Log(
   568→			"msg", "write block resulted in empty block",
   569→			"mint", meta.MinTime,
   570→			"maxt", meta.MaxTime,
   571→			"duration", time.Since(start),
   572→		)
   573→		return ulid.ULID{}, nil
   574→	}
   575→
   576→	level.Info(c.logger).Log(
   577→		"msg", "write block",
   578→		"mint", meta.MinTime,
   579→		"maxt", meta.MaxTime,
   580→		"ulid", meta.ULID,
   581→		"duration", time.Since(start),
   582→		"ooo", meta.Compaction.FromOutOfOrder(),
   583→	)
   584→	return uid, nil
   585→}
   586→
   587→// instrumentedChunkWriter is used for level 1 compactions to record statistics
   588→// about compacted chunks.
   589→type instrumentedChunkWriter struct {
   590→	ChunkWriter
   591→
   592→	size    prometheus.Histogram
   593→	samples prometheus.Histogram
   594→	trange  prometheus.Histogram
   595→}
   596→
   597→func (w *instrumentedChunkWriter) WriteChunks(chunks ...chunks.Meta) error {
   598→	for _, c := range chunks {
   599→		w.size.Observe(float64(len(c.Chunk.Bytes())))
   600→		w.samples.Observe(float64(c.Chunk.NumSamples()))
   601→		w.trange.Observe(float64(c.MaxTime - c.MinTime))
   602→	}
   603→	return w.ChunkWriter.WriteChunks(chunks...)
   604→}
   605→
   606→// write creates a new block that is the union of the provided blocks into dir.
   607→func (c *LeveledCompactor) write(dest string, meta *BlockMeta, blockPopulator BlockPopulator, blocks ...BlockReader) (err error) {
   608→	dir := filepath.Join(dest, meta.ULID.String())
   609→	tmp := dir + tmpForCreationBlockDirSuffix
   610→	var closers []io.Closer
   611→	defer func(t time.Time) {
   612→		err = tsdb_errors.NewMulti(err, tsdb_errors.CloseAll(closers)).Err()
   613→
   614→		// RemoveAll returns no error when tmp doesn't exist so it is safe to always run it.
   615→		if err := os.RemoveAll(tmp); err != nil {
   616→			level.Error(c.logger).Log("msg", "removed tmp folder after failed compaction", "err", err.Error())
   617→		}
   618→		c.metrics.Ran.Inc()
   619→		c.metrics.Duration.Observe(time.Since(t).Seconds())
   620→	}(time.Now())
   621→
   622→	if err = os.RemoveAll(tmp); err != nil {
   623→		return err
   624→	}
   625→
   626→	if err = os.MkdirAll(tmp, 0o777); err != nil {
   627→		return err
   628→	}
   629→
   630→	// Populate chunk and index files into temporary directory with
   631→	// data of all blocks.
   632→	var chunkw ChunkWriter
   633→
   634→	chunkw, err = chunks.NewWriterWithSegSize(chunkDir(tmp), c.maxBlockChunkSegmentSize)
   635→	if err != nil {
   636→		return fmt.Errorf("open chunk writer: %w", err)
   637→	}
   638→	closers = append(closers, chunkw)
   639→	// Record written chunk sizes on level 1 compactions.
   640→	if meta.Compaction.Level == 1 {
   641→		chunkw = &instrumentedChunkWriter{
   642→			ChunkWriter: chunkw,
   643→			size:        c.metrics.ChunkSize,
   644→			samples:     c.metrics.ChunkSamples,
   645→			trange:      c.metrics.ChunkRange,
   646→		}
   647→	}
   648→
   649→	indexw, err := index.NewWriterWithEncoder(c.ctx, filepath.Join(tmp, indexFilename), c.postingsEncoder)
   650→	if err != nil {
   651→		return fmt.Errorf("open index writer: %w", err)
   652→	}
   653→	closers = append(closers, indexw)
   654→
   655→	if err := blockPopulator.PopulateBlock(c.ctx, c.metrics, c.logger, c.chunkPool, c.mergeFunc, blocks, meta, indexw, chunkw); err != nil {
   656→		return fmt.Errorf("populate block: %w", err)
   657→	}
   658→
   659→	select {
   660→	case <-c.ctx.Done():
   661→		return c.ctx.Err()
   662→	default:
   663→	}
   664→
   665→	// We are explicitly closing them here to check for error even
   666→	// though these are covered under defer. This is because in Windows,
   667→	// you cannot delete these unless they are closed and the defer is to
   668→	// make sure they are closed if the function exits due to an error above.
   669→	errs := tsdb_errors.NewMulti()
   670→	for _, w := range closers {
   671→		errs.Add(w.Close())
   672→	}
   673→	closers = closers[:0] // Avoid closing the writers twice in the defer.
   674→	if errs.Err() != nil {
   675→		return errs.Err()
   676→	}
   677→
   678→	// Populated block is empty, so exit early.
   679→	if meta.Stats.NumSamples == 0 {
   680→		return nil
   681→	}
   682→
   683→	if _, err = writeMetaFile(c.logger, tmp, meta); err != nil {
   684→		return fmt.Errorf("write merged meta: %w", err)
   685→	}
   686→
   687→	// Create an empty tombstones file.
   688→	if _, err := tombstones.WriteFile(c.logger, tmp, tombstones.NewMemTombstones()); err != nil {
   689→		return fmt.Errorf("write new tombstones file: %w", err)
   690→	}
   691→
   692→	df, err := fileutil.OpenDir(tmp)
   693→	if err != nil {
   694→		return fmt.Errorf("open temporary block dir: %w", err)
   695→	}
   696→	defer func() {
   697→		if df != nil {
   698→			df.Close()
   699→		}
   700→	}()
   701→
   702→	if err := df.Sync(); err != nil {
   703→		return fmt.Errorf("sync temporary dir file: %w", err)
   704→	}
   705→
   706→	// Close temp dir before rename block dir (for windows platform).
   707→	if err = df.Close(); err != nil {
   708→		return fmt.Errorf("close temporary dir: %w", err)
   709→	}
   710→	df = nil
   711→
   712→	// Block successfully written, make it visible in destination dir by moving it from tmp one.
   713→	if err := fileutil.Replace(tmp, dir); err != nil {
   714→		return fmt.Errorf("rename block dir: %w", err)
   715→	}
   716→
   717→	return nil
   718→}
   719→
   720→type BlockPopulator interface {
   721→	PopulateBlock(ctx context.Context, metrics *CompactorMetrics, logger log.Logger, chunkPool chunkenc.Pool, mergeFunc storage.VerticalChunkSeriesMergeFunc, blocks []BlockReader, meta *BlockMeta, indexw IndexWriter, chunkw ChunkWriter) error
   722→}
   723→
   724→type DefaultBlockPopulator struct{}
   725→
   726→// PopulateBlock fills the index and chunk writers with new data gathered as the union
   727→// of the provided blocks. It returns meta information for the new block.
   728→// It expects sorted blocks input by mint.
   729→func (c DefaultBlockPopulator) PopulateBlock(ctx context.Context, metrics *CompactorMetrics, logger log.Logger, chunkPool chunkenc.Pool, mergeFunc storage.VerticalChunkSeriesMergeFunc, blocks []BlockReader, meta *BlockMeta, indexw IndexWriter, chunkw ChunkWriter) (err error) {
   730→	if len(blocks) == 0 {
   731→		return errors.New("cannot populate block from no readers")
   732→	}
   733→
   734→	var (
   735→		sets        []storage.ChunkSeriesSet
   736→		symbols     index.StringIter
   737→		closers     []io.Closer
   738→		overlapping bool
   739→	)
   740→	defer func() {
   741→		errs := tsdb_errors.NewMulti(err)
   742→		if cerr := tsdb_errors.CloseAll(closers); cerr != nil {
   743→			errs.Add(fmt.Errorf("close: %w", cerr))
   744→		}
   745→		err = errs.Err()
   746→		metrics.PopulatingBlocks.Set(0)
   747→	}()
   748→	metrics.PopulatingBlocks.Set(1)
   749→
   750→	globalMaxt := blocks[0].Meta().MaxTime
   751→	for i, b := range blocks {
   752→		select {
   753→		case <-ctx.Done():
   754→			return ctx.Err()
   755→		default:
   756→		}
   757→
   758→		if !overlapping {
   759→			if i > 0 && b.Meta().MinTime < globalMaxt {
   760→				metrics.OverlappingBlocks.Inc()
   761→				overlapping = true
   762→				level.Info(logger).Log("msg", "Found overlapping blocks during compaction", "ulid", meta.ULID)
   763→			}
   764→			if b.Meta().MaxTime > globalMaxt {
   765→				globalMaxt = b.Meta().MaxTime
   766→			}
   767→		}
   768→
   769→		indexr, err := b.Index()
   770→		if err != nil {
   771→			return fmt.Errorf("open index reader for block %+v: %w", b.Meta(), err)
   772→		}
   773→		closers = append(closers, indexr)
   774→
   775→		chunkr, err := b.Chunks()
   776→		if err != nil {
   777→			return fmt.Errorf("open chunk reader for block %+v: %w", b.Meta(), err)
   778→		}
   779→		closers = append(closers, chunkr)
   780→
   781→		tombsr, err := b.Tombstones()
   782→		if err != nil {
   783→			return fmt.Errorf("open tombstone reader for block %+v: %w", b.Meta(), err)
   784→		}
   785→		closers = append(closers, tombsr)
   786→
   787→		k, v := index.AllPostingsKey()
   788→		all, err := indexr.Postings(ctx, k, v)
   789→		if err != nil {
   790→			return err
   791→		}
   792→		all = indexr.SortedPostings(all)
   793→		// Blocks meta is half open: [min, max), so subtract 1 to ensure we don't hold samples with exact meta.MaxTime timestamp.
   794→		sets = append(sets, NewBlockChunkSeriesSet(b.Meta().ULID, indexr, chunkr, tombsr, all, meta.MinTime, meta.MaxTime-1, false))
   795→		syms := indexr.Symbols()
   796→		if i == 0 {
   797→			symbols = syms
   798→			continue
   799→		}
   800→		symbols = NewMergedStringIter(symbols, syms)
   801→	}
   802→
   803→	for symbols.Next() {
   804→		if err := indexw.AddSymbol(symbols.At()); err != nil {
   805→			return fmt.Errorf("add symbol: %w", err)
   806→		}
   807→	}
   808→	if err := symbols.Err(); err != nil {
   809→		return fmt.Errorf("next symbol: %w", err)
   810→	}
   811→
   812→	var (
   813→		ref      = storage.SeriesRef(0)
   814→		chks     []chunks.Meta
   815→		chksIter chunks.Iterator
   816→	)
   817→
   818→	set := sets[0]
   819→	if len(sets) > 1 {
   820→		// Merge series using specified chunk series merger.
   821→		// The default one is the compacting series merger.
   822→		set = storage.NewMergeChunkSeriesSet(sets, mergeFunc)
   823→	}
   824→
   825→	// Iterate over all sorted chunk series.
   826→	for set.Next() {
   827→		select {
   828→		case <-ctx.Done():
   829→			return ctx.Err()
   830→		default:
   831→		}
   832→		s := set.At()
   833→		chksIter = s.Iterator(chksIter)
   834→		chks = chks[:0]
   835→		for chksIter.Next() {
   836→			// We are not iterating in streaming way over chunk as
   837→			// it's more efficient to do bulk write for index and
   838→			// chunk file purposes.
   839→			chks = append(chks, chksIter.At())
   840→		}
   841→		if err := chksIter.Err(); err != nil {
   842→			return fmt.Errorf("chunk iter: %w", err)
   843→		}
   844→
   845→		// Skip the series with all deleted chunks.
   846→		if len(chks) == 0 {
   847→			continue
   848→		}
   849→
   850→		if err := chunkw.WriteChunks(chks...); err != nil {
   851→			return fmt.Errorf("write chunks: %w", err)
   852→		}
   853→		if err := indexw.AddSeries(ref, s.Labels(), chks...); err != nil {
   854→			return fmt.Errorf("add series: %w", err)
   855→		}
   856→
   857→		meta.Stats.NumChunks += uint64(len(chks))
   858→		meta.Stats.NumSeries++
   859→		for _, chk := range chks {
   860→			meta.Stats.NumSamples += uint64(chk.Chunk.NumSamples())
   861→		}
   862→
   863→		for _, chk := range chks {
   864→			if err := chunkPool.Put(chk.Chunk); err != nil {
   865→				return fmt.Errorf("put chunk: %w", err)
   866→			}
   867→		}
   868→		ref++
   869→	}
   870→	if err := set.Err(); err != nil {
   871→		return fmt.Errorf("iterate compaction set: %w", err)
   872→	}
   873→
   874→	return nil
   875→}
   876→

