   152→func (b *writeBenchmark) ingestScrapes(lbls []labels.Labels, scrapeCount int) (uint64, error) {
   153→	var total atomic.Uint64
   154→
   155→	for i := 0; i < scrapeCount; i += 100 {
   156→		var wg sync.WaitGroup
   157→		lbls := lbls
   158→		for len(lbls) > 0 {
   159→			l := 1000
   160→			if len(lbls) < 1000 {
   161→				l = len(lbls)
   162→			}
   163→			batch := lbls[:l]
   164→			lbls = lbls[l:]
   165→
   166→			wg.Add(1)
   167→			go func() {
   168→				defer wg.Done()
   169→
   170→				n, err := b.ingestScrapesShard(batch, 100, int64(timeDelta*i))
   171→				if err != nil {
   172→					// exitWithError(err)
   173→					fmt.Println(" err", err)
   174→				}
   175→				total.Add(n)
   176→			}()
   177→		}
   178→		wg.Wait()
   179→	}
   180→	fmt.Println("ingestion completed")
   181→
   182→	return total.Load(), nil
   183→}
