   233→func (b *writeBenchmark) startProfiling() error {
   234→	var err error
   235→
   236→	// Start CPU profiling.
   237→	b.cpuprof, err = os.Create(filepath.Join(b.outPath, "cpu.prof"))
   238→	if err != nil {
   239→		return fmt.Errorf("bench: could not create cpu profile: %w", err)
   240→	}
   241→	if err := pprof.StartCPUProfile(b.cpuprof); err != nil {
   242→		return fmt.Errorf("bench: could not start CPU profile: %w", err)
   243→	}
   244→
   245→	// Start memory profiling.
   246→	b.memprof, err = os.Create(filepath.Join(b.outPath, "mem.prof"))
   247→	if err != nil {
   248→		return fmt.Errorf("bench: could not create memory profile: %w", err)
   249→	}
   250→	runtime.MemProfileRate = 64 * 1024
   251→
   252→	// Start fatal profiling.
   253→	b.blockprof, err = os.Create(filepath.Join(b.outPath, "block.prof"))
   254→	if err != nil {
   255→		return fmt.Errorf("bench: could not create block profile: %w", err)
   256→	}
   257→	runtime.SetBlockProfileRate(20)
   258→
   259→	b.mtxprof, err = os.Create(filepath.Join(b.outPath, "mutex.prof"))
   260→	if err != nil {
   261→		return fmt.Errorf("bench: could not create mutex profile: %w", err)
   262→	}
   263→	runtime.SetMutexProfileFraction(20)
   264→	return nil
   265→}
   266→
   267→func (b *writeBenchmark) stopProfiling() error {
   268→	if b.cpuprof != nil {
   269→		pprof.StopCPUProfile()
   270→		b.cpuprof.Close()
   271→		b.cpuprof = nil
   272→	}
   273→	if b.memprof != nil {
   274→		if err := pprof.Lookup("heap").WriteTo(b.memprof, 0); err != nil {
   275→			return fmt.Errorf("error writing mem profile: %w", err)
   276→		}
   277→		b.memprof.Close()
   278→		b.memprof = nil
   279→	}
   280→	if b.blockprof != nil {
   281→		if err := pprof.Lookup("block").WriteTo(b.blockprof, 0); err != nil {
   282→			return fmt.Errorf("error writing block profile: %w", err)
   283→		}
   284→		b.blockprof.Close()
   285→		b.blockprof = nil
   286→		runtime.SetBlockProfileRate(0)
   287→	}
   288→	if b.mtxprof != nil {
   289→		if err := pprof.Lookup("mutex").WriteTo(b.mtxprof, 0); err != nil {
   290→			return fmt.Errorf("error writing mutex profile: %w", err)
   291→		}
   292→		b.mtxprof.Close()
   293→		b.mtxprof = nil
   294→		runtime.SetMutexProfileFraction(0)
   295→	}
   296→	return nil
   297→}
