   416→func analyzeBlock(ctx context.Context, path, blockID string, limit int, runExtended bool, matchers string) error {
   417→	var (
   418→		selectors []*labels.Matcher
   419→		err       error
   420→	)
   421→	if len(matchers) > 0 {
   422→		selectors, err = parser.ParseMetricSelector(matchers)
   423→		if err != nil {
   424→			return err
   425→		}
   426→	}
   427→	db, block, err := openBlock(path, blockID)
   428→	if err != nil {
   429→		return err
   430→	}
   431→	defer func() {
   432→		err = tsdb_errors.NewMulti(err, db.Close()).Err()
   433→	}()
   434→
   435→	meta := block.Meta()
   436→	fmt.Printf("Block ID: %s\n", meta.ULID)
   437→	// Presume 1ms resolution that Prometheus uses.
   438→	fmt.Printf("Duration: %s\n", (time.Duration(meta.MaxTime-meta.MinTime) * 1e6).String())
   439→	fmt.Printf("Total Series: %d\n", meta.Stats.NumSeries)
   440→	if len(matchers) > 0 {
   441→		fmt.Printf("Matcher: %s\n", matchers)
   442→	}
   443→	ir, err := block.Index()
   444→	if err != nil {
   445→		return err
   446→	}
   447→	defer ir.Close()
   448→
   449→	allLabelNames, err := ir.LabelNames(ctx, selectors...)
   450→	if err != nil {
   451→		return err
   452→	}
   453→	fmt.Printf("Label names: %d\n", len(allLabelNames))
   454→
   455→	type postingInfo struct {
   456→		key    string
   457→		metric uint64
   458→	}
   459→	postingInfos := []postingInfo{}
   460→
   461→	printInfo := func(postingInfos []postingInfo) {
   462→		slices.SortFunc(postingInfos, func(a, b postingInfo) int {
   463→			switch {
   464→			case b.metric < a.metric:
   465→				return -1
   466→			case b.metric > a.metric:
   467→				return 1
   468→			default:
   469→				return 0
   470→			}
   471→		})
   472→
   473→		for i, pc := range postingInfos {
   474→			if i >= limit {
   475→				break
   476→			}
   477→			fmt.Printf("%d %s\n", pc.metric, pc.key)
   478→		}
   479→	}
   480→
   481→	labelsUncovered := map[string]uint64{}
   482→	labelpairsUncovered := map[string]uint64{}
   483→	labelpairsCount := map[string]uint64{}
   484→	entries := 0
   485→	var (
   486→		p    index.Postings
   487→		refs []storage.SeriesRef
   488→	)
   489→	if len(matchers) > 0 {
   490→		p, err = tsdb.PostingsForMatchers(ctx, ir, selectors...)
   491→		if err != nil {
   492→			return err
   493→		}
   494→		// Expand refs first and cache in memory.
   495→		// So later we don't have to expand again.
   496→		refs, err = index.ExpandPostings(p)
   497→		if err != nil {
   498→			return err
   499→		}
   500→		fmt.Printf("Matched series: %d\n", len(refs))
   501→		p = index.NewListPostings(refs)
   502→	} else {
   503→		p, err = ir.Postings(ctx, "", "") // The special all key.
   504→		if err != nil {
   505→			return err
   506→		}
   507→	}
   508→
   509→	chks := []chunks.Meta{}
   510→	builder := labels.ScratchBuilder{}
   511→	for p.Next() {
   512→		if err = ir.Series(p.At(), &builder, &chks); err != nil {
   513→			return err
   514→		}
   515→		// Amount of the block time range not covered by this series.
   516→		uncovered := uint64(meta.MaxTime-meta.MinTime) - uint64(chks[len(chks)-1].MaxTime-chks[0].MinTime)
   517→		builder.Labels().Range(func(lbl labels.Label) {
   518→			key := lbl.Name + "=" + lbl.Value
   519→			labelsUncovered[lbl.Name] += uncovered
   520→			labelpairsUncovered[key] += uncovered
   521→			labelpairsCount[key]++
   522→			entries++
   523→		})
   524→	}
   525→	if p.Err() != nil {
   526→		return p.Err()
   527→	}
   528→	fmt.Printf("Postings (unique label pairs): %d\n", len(labelpairsUncovered))
   529→	fmt.Printf("Postings entries (total label pairs): %d\n", entries)
   530→
   531→	postingInfos = postingInfos[:0]
   532→	for k, m := range labelpairsUncovered {
   533→		postingInfos = append(postingInfos, postingInfo{k, uint64(float64(m) / float64(meta.MaxTime-meta.MinTime))})
   534→	}
   535→
   536→	fmt.Printf("\nLabel pairs most involved in churning:\n")
   537→	printInfo(postingInfos)
   538→
   539→	postingInfos = postingInfos[:0]
   540→	for k, m := range labelsUncovered {
   541→		postingInfos = append(postingInfos, postingInfo{k, uint64(float64(m) / float64(meta.MaxTime-meta.MinTime))})
   542→	}
   543→
   544→	fmt.Printf("\nLabel names most involved in churning:\n")
   545→	printInfo(postingInfos)
   546→
   547→	postingInfos = postingInfos[:0]
   548→	for k, m := range labelpairsCount {
   549→		postingInfos = append(postingInfos, postingInfo{k, m})
   550→	}
   551→
   552→	fmt.Printf("\nMost common label pairs:\n")
   553→	printInfo(postingInfos)
   554→
   555→	postingInfos = postingInfos[:0]
   556→	for _, n := range allLabelNames {
   557→		values, err := ir.SortedLabelValues(ctx, n, selectors...)
   558→		if err != nil {
   559→			return err
   560→		}
   561→		var cumulativeLength uint64
   562→		for _, str := range values {
   563→			cumulativeLength += uint64(len(str))
   564→		}
   565→		postingInfos = append(postingInfos, postingInfo{n, cumulativeLength})
   566→	}
   567→
   568→	fmt.Printf("\nLabel names with highest cumulative label value length:\n")
   569→	printInfo(postingInfos)
   570→
   571→	postingInfos = postingInfos[:0]
   572→	for _, n := range allLabelNames {
   573→		lv, err := ir.SortedLabelValues(ctx, n, selectors...)
   574→		if err != nil {
   575→			return err
   576→		}
   577→		postingInfos = append(postingInfos, postingInfo{n, uint64(len(lv))})
   578→	}
   579→	fmt.Printf("\nHighest cardinality labels:\n")
   580→	printInfo(postingInfos)
   581→
   582→	postingInfos = postingInfos[:0]
   583→	lv, err := ir.SortedLabelValues(ctx, "__name__", selectors...)
   584→	if err != nil {
   585→		return err
   586→	}
   587→	for _, n := range lv {
   588→		postings, err := ir.Postings(ctx, "__name__", n)
   589→		if err != nil {
   590→			return err
   591→		}
   592→		postings = index.Intersect(postings, index.NewListPostings(refs))
   593→		count := 0
   594→		for postings.Next() {
   595→			count++
   596→		}
   597→		if postings.Err() != nil {
   598→			return postings.Err()
   599→		}
   600→		postingInfos = append(postingInfos, postingInfo{n, uint64(count)})
   601→	}
   602→	fmt.Printf("\nHighest cardinality metric names:\n")
   603→	printInfo(postingInfos)
   604→
   605→	if runExtended {
   606→		return analyzeCompaction(ctx, block, ir, selectors)
   607→	}
   608→
   609→	return nil
   610→}
   611→
   612→func analyzeCompaction(ctx context.Context, block tsdb.BlockReader, indexr tsdb.IndexReader, matchers []*labels.Matcher) (err error) {
   613→	var postingsr index.Postings
   614→	if len(matchers) > 0 {
   615→		postingsr, err = tsdb.PostingsForMatchers(ctx, indexr, matchers...)
   616→	} else {
   617→		n, v := index.AllPostingsKey()
   618→		postingsr, err = indexr.Postings(ctx, n, v)
   619→	}
   620→	if err != nil {
   621→		return err
   622→	}
   623→
   624→	chunkr, err := block.Chunks()
   625→	if err != nil {
   626→		return err
   627→	}
   628→	defer func() {
   629→		err = tsdb_errors.NewMulti(err, chunkr.Close()).Err()
   630→	}()
   631→
   632→	totalChunks := 0
   633→	floatChunkSamplesCount := make([]int, 0)
   634→	floatChunkSize := make([]int, 0)
   635→	histogramChunkSamplesCount := make([]int, 0)
   636→	histogramChunkSize := make([]int, 0)
   637→	histogramChunkBucketsCount := make([]int, 0)
   638→	var builder labels.ScratchBuilder
   639→	for postingsr.Next() {
   640→		var chks []chunks.Meta
   641→		if err := indexr.Series(postingsr.At(), &builder, &chks); err != nil {
   642→			return err
   643→		}
   644→
   645→		for _, chk := range chks {
   646→			// Load the actual data of the chunk.
   647→			chk, iterable, err := chunkr.ChunkOrIterable(chk)
   648→			if err != nil {
   649→				return err
   650→			}
   651→			// Chunks within blocks should not need to be re-written, so an
   652→			// iterable is not expected to be returned from the chunk reader.
   653→			if iterable != nil {
   654→				return errors.New("ChunkOrIterable should not return an iterable when reading a block")
   655→			}
   656→			switch chk.Encoding() {
   657→			case chunkenc.EncXOR:
   658→				floatChunkSamplesCount = append(floatChunkSamplesCount, chk.NumSamples())
