   711→func dumpSamples(ctx context.Context, path string, mint, maxt int64, match []string, formatter SeriesSetFormatter) (err error) {
   712→	db, err := tsdb.OpenDBReadOnly(path, nil)
   713→	if err != nil {
   714→		return err
   715→	}
   716→	defer func() {
   717→		err = tsdb_errors.NewMulti(err, db.Close()).Err()
   718→	}()
   719→	q, err := db.Querier(mint, maxt)
   720→	if err != nil {
   721→		return err
   722→	}
   723→	defer q.Close()
   724→
   725→	matcherSets, err := parser.ParseMetricSelectors(match)
   726→	if err != nil {
   727→		return err
   728→	}
   729→
   730→	var ss storage.SeriesSet
   731→	if len(matcherSets) > 1 {
   732→		var sets []storage.SeriesSet
   733→		for _, mset := range matcherSets {
   734→			sets = append(sets, q.Select(ctx, true, nil, mset...))
   735→		}
   736→		ss = storage.NewMergeSeriesSet(sets, storage.ChainedSeriesMerge)
   737→	} else {
