   310→func readPrometheusLabels(r io.Reader, n int) ([]labels.Labels, error) {
   311→	scanner := bufio.NewScanner(r)
   312→
   313→	var mets []labels.Labels
   314→	hashes := map[uint64]struct{}{}
   315→	i := 0
   316→
   317→	for scanner.Scan() && i < n {
   318→		m := make([]labels.Label, 0, 10)
   319→
   320→		r := strings.NewReplacer("\"", "", "{", "", "}", "")
   321→		s := r.Replace(scanner.Text())
   322→
   323→		labelChunks := strings.Split(s, ",")
   324→		for _, labelChunk := range labelChunks {
   325→			split := strings.Split(labelChunk, ":")
   326→			m = append(m, labels.Label{Name: split[0], Value: split[1]})
   327→		}
   328→		ml := labels.New(m...) // This sorts by name - order of the k/v labels matters, don't assume we'll always receive them already sorted.
   329→		h := ml.Hash()
   330→		if _, ok := hashes[h]; ok {
   331→			continue
   332→		}
   333→		mets = append(mets, ml)
   334→		hashes[h] = struct{}{}
   335→		i++
   336→	}
   337→	return mets, nil
   338→}
