   555→	postingInfos = postingInfos[:0]
   556→	for _, n := range allLabelNames {
   557→		values, err := ir.SortedLabelValues(ctx, n, selectors...)
   558→		if err != nil {
   559→			return err
   560→		}
   561→		var cumulativeLength uint64
   562→		for _, str := range values {
   563→			cumulativeLength += uint64(len(str))
   564→		}
   565→		postingInfos = append(postingInfos, postingInfo{n, cumulativeLength})
   566→	}
   567→
   568→	fmt.Printf("\nLabel names with highest cumulative label value length:\n")
   569→	printInfo(postingInfos)
   570→
   571→	postingInfos = postingInfos[:0]
   572→	for _, n := range allLabelNames {
   573→		lv, err := ir.SortedLabelValues(ctx, n, selectors...)
   574→		if err != nil {
   575→			return err
   576→		}
   577→		postingInfos = append(postingInfos, postingInfo{n, uint64(len(lv))})
   578→	}
   579→	fmt.Printf("\nHighest cardinality labels:\n")
   580→	printInfo(postingInfos)
   581→
   582→	postingInfos = postingInfos[:0]
   583→	lv, err := ir.SortedLabelValues(ctx, "__name__", selectors...)
   584→	if err != nil {
   585→		return err
   586→	}
   587→	for _, n := range lv {
   588→		postings, err := ir.Postings(ctx, "__name__", n)
   589→		if err != nil {
   590→			return err
   591→		}
   592→		postings = index.Intersect(postings, index.NewListPostings(refs))
   593→		count := 0
   594→		for postings.Next() {
   595→			count++
   596→		}
   597→		if postings.Err() != nil {
   598→			return postings.Err()
   599→		}
   600→		postingInfos = append(postingInfos, postingInfo{n, uint64(count)})
   601→	}
   602→	fmt.Printf("\nHighest cardinality metric names:\n")
   603→	printInfo(postingInfos)
   604→
   605→	if runExtended {
   606→		return analyzeCompaction(ctx, block, ir, selectors)
   607→	}
   608→
   609→	return nil
   610→}
   611→
   612→func analyzeCompaction(ctx context.Context, block tsdb.BlockReader, indexr tsdb.IndexReader, matchers []*labels.Matcher) (err error) {
   613→	var postingsr index.Postings
   614→	if len(matchers) > 0 {
   615→		postingsr, err = tsdb.PostingsForMatchers(ctx, indexr, matchers...)
   616→	} else {
   617→		n, v := index.AllPostingsKey()
   618→		postingsr, err = indexr.Postings(ctx, n, v)
   619→	}
   620→	if err != nil {
   621→		return err
   622→	}
   623→
   624→	chunkr, err := block.Chunks()
   625→	if err != nil {
   626→		return err
   627→	}
   628→	defer func() {
   629→		err = tsdb_errors.NewMulti(err, chunkr.Close()).Err()
   630→	}()
   631→
   632→	totalChunks := 0
   633→	floatChunkSamplesCount := make([]int, 0)
   634→	floatChunkSize := make([]int, 0)
   635→	histogramChunkSamplesCount := make([]int, 0)
   636→	histogramChunkSize := make([]int, 0)
   637→	histogramChunkBucketsCount := make([]int, 0)
   638→	var builder labels.ScratchBuilder
   639→	for postingsr.Next() {
   640→		var chks []chunks.Meta
   641→		if err := indexr.Series(postingsr.At(), &builder, &chks); err != nil {
   642→			return err
   643→		}
   644→
   645→		for _, chk := range chks {
   646→			// Load the actual data of the chunk.
   647→			chk, iterable, err := chunkr.ChunkOrIterable(chk)
   648→			if err != nil {
   649→				return err
   650→			}
   651→			// Chunks within blocks should not need to be re-written, so an
   652→			// iterable is not expected to be returned from the chunk reader.
   653→			if iterable != nil {
   654→				return errors.New("ChunkOrIterable should not return an iterable when reading a block")
   655→			}
   656→			switch chk.Encoding() {
   657→			case chunkenc.EncXOR:
   658→				floatChunkSamplesCount = append(floatChunkSamplesCount, chk.NumSamples())
   659→				floatChunkSize = append(floatChunkSize, len(chk.Bytes()))
   660→			case chunkenc.EncFloatHistogram:
   661→				histogramChunkSamplesCount = append(histogramChunkSamplesCount, chk.NumSamples())
   662→				histogramChunkSize = append(histogramChunkSize, len(chk.Bytes()))
   663→				fhchk, ok := chk.(*chunkenc.FloatHistogramChunk)
   664→				if !ok {
   665→					return fmt.Errorf("chunk is not FloatHistogramChunk")
   666→				}
   667→				it := fhchk.Iterator(nil)
   668→				bucketCount := 0
   669→				for it.Next() == chunkenc.ValFloatHistogram {
   670→					_, f := it.AtFloatHistogram(nil)
   671→					bucketCount += len(f.PositiveBuckets)
   672→					bucketCount += len(f.NegativeBuckets)
   673→				}
   674→				histogramChunkBucketsCount = append(histogramChunkBucketsCount, bucketCount)
   675→			case chunkenc.EncHistogram:
   676→				histogramChunkSamplesCount = append(histogramChunkSamplesCount, chk.NumSamples())
   677→				histogramChunkSize = append(histogramChunkSize, len(chk.Bytes()))
   678→				hchk, ok := chk.(*chunkenc.HistogramChunk)
   679→				if !ok {
   680→					return fmt.Errorf("chunk is not HistogramChunk")
   681→				}
   682→				it := hchk.Iterator(nil)
   683→				bucketCount := 0
   684→				for it.Next() == chunkenc.ValHistogram {
   685→					_, f := it.AtHistogram(nil)
   686→					bucketCount += len(f.PositiveBuckets)
   687→					bucketCount += len(f.NegativeBuckets)
   688→				}
   689→				histogramChunkBucketsCount = append(histogramChunkBucketsCount, bucketCount)
   690→			}
   691→			totalChunks++
   692→		}
   693→	}
   694→
   695→	fmt.Printf("\nCompaction analysis:\n")
   696→	fmt.Println()
   697→	displayHistogram("samples per float chunk", floatChunkSamplesCount, totalChunks)
   698→
   699→	displayHistogram("bytes per float chunk", floatChunkSize, totalChunks)
   700→
   701→	displayHistogram("samples per histogram chunk", histogramChunkSamplesCount, totalChunks)
   702→
   703→	displayHistogram("bytes per histogram chunk", histogramChunkSize, totalChunks)
   704→
   705→	displayHistogram("buckets per histogram chunk", histogramChunkBucketsCount, totalChunks)
   706→	return nil
   707→}
   708→
   709→type SeriesSetFormatter func(series storage.SeriesSet) error
   710→
   711→func dumpSamples(ctx context.Context, path string, mint, maxt int64, match []string, formatter SeriesSetFormatter) (err error) {
   712→	db, err := tsdb.OpenDBReadOnly(path, nil)
   713→	if err != nil {
   714→		return err
   715→	}
   716→	defer func() {
   717→		err = tsdb_errors.NewMulti(err, db.Close()).Err()
   718→	}()
   719→	q, err := db.Querier(mint, maxt)
   720→	if err != nil {
   721→		return err
   722→	}
   723→	defer q.Close()
   724→
   725→	matcherSets, err := parser.ParseMetricSelectors(match)
   726→	if err != nil {
   727→		return err
   728→	}
   729→
   730→	var ss storage.SeriesSet
   731→	if len(matcherSets) > 1 {
   732→		var sets []storage.SeriesSet
   733→		for _, mset := range matcherSets {
   734→			sets = append(sets, q.Select(ctx, true, nil, mset...))
   735→		}
   736→		ss = storage.NewMergeSeriesSet(sets, storage.ChainedSeriesMerge)
   737→	} else {
   738→		ss = q.Select(ctx, false, nil, matcherSets[0]...)
   739→	}
   740→
   741→	err = formatter(ss)
   742→	if err != nil {
   743→		return err
   744→	}
   745→
   746→	if ws := ss.Warnings(); len(ws) > 0 {
   747→		return tsdb_errors.NewMulti(ws.AsErrors()...).Err()
   748→	}
   749→
   750→	if ss.Err() != nil {
   751→		return ss.Err()
   752→	}
   753→	return nil
   754→}
   755→
   756→func formatSeriesSet(ss storage.SeriesSet) error {
   757→	for ss.Next() {
   758→		series := ss.At()
   759→		lbs := series.Labels()
   760→		it := series.Iterator(nil)
   761→		for it.Next() == chunkenc.ValFloat {
   762→			ts, val := it.At()
   763→			fmt.Printf("%s %g %d\n", lbs, val, ts)
   764→		}
   765→		for it.Next() == chunkenc.ValFloatHistogram {
   766→			ts, fh := it.AtFloatHistogram(nil)
   767→			fmt.Printf("%s %s %d\n", lbs, fh.String(), ts)
   768→		}
   769→		for it.Next() == chunkenc.ValHistogram {
   770→			ts, h := it.AtHistogram(nil)
   771→			fmt.Printf("%s %s %d\n", lbs, h.String(), ts)
   772→		}
   773→		if it.Err() != nil {
   774→			return ss.Err()
   775→		}
   776→	}
   777→	return nil
   778→}
   779→
   780→// CondensedString is labels.Labels.String() without spaces after the commas.
   781→func CondensedString(ls labels.Labels) string {
   782→	var b bytes.Buffer
   783→
   784→	b.WriteByte('{')
   785→	i := 0
   786→	ls.Range(func(l labels.Label) {
   787→		if i > 0 {
   788→			b.WriteByte(',')
   789→		}
   790→		b.WriteString(l.Name)
   791→		b.WriteByte('=')
   792→		b.WriteString(strconv.Quote(l.Value))
   793→		i++
   794→	})
   795→	b.WriteByte('}')
   796→	return b.String()
   797→}
   798→
   799→func formatSeriesSetOpenMetrics(ss storage.SeriesSet) error {
   800→	for ss.Next() {
   801→		series := ss.At()
   802→		lbs := series.Labels()
   803→		metricName := lbs.Get(labels.MetricName)
   804→		lbs = lbs.DropMetricName()
   805→		it := series.Iterator(nil)
   806→		for it.Next() == chunkenc.ValFloat {
   807→			ts, val := it.At()
   808→			fmt.Printf("%s%s %g %.3f\n", metricName, CondensedString(lbs), val, float64(ts)/1000)
   809→		}
   810→		if it.Err() != nil {
   811→			return ss.Err()
   812→		}
   813→	}
   814→	fmt.Println("# EOF")
   815→	return nil
   816→}
   817→
   818→func checkErr(err error) int {
   819→	if err != nil {
   820→		fmt.Fprintln(os.Stderr, err)
   821→		return 1
   822→	}
   823→	return 0
   824→}
   825→
   826→func backfillOpenMetrics(path, outputDir string, humanReadable, quiet bool, maxBlockDuration time.Duration) int {
   827→	inputFile, err := fileutil.OpenMmapFile(path)
   828→	if err != nil {
   829→		return checkErr(err)
   830→	}
   831→	defer inputFile.Close()
   832→
   833→	if err := os.MkdirAll(outputDir, 0o777); err != nil {
   834→		return checkErr(fmt.Errorf("create output dir: %w", err))
   835→	}
   836→
   837→	return checkErr(backfill(5000, inputFile.Bytes(), outputDir, humanReadable, quiet, maxBlockDuration))
   838→}
   839→
   840→func displayHistogram(dataType string, datas []int, total int) {
   841→	if len(datas) == 0 {
   842→		fmt.Printf("%s: N/A\n\n", dataType)
   843→		return
   844→	}
   845→	slices.Sort(datas)
   846→	start, end, step := generateBucket(datas[0], datas[len(datas)-1])
   847→	sum := 0
   848→	buckets := make([]int, (end-start)/step+1)
   849→	maxCount := 0
   850→	for _, c := range datas {
   851→		sum += c
   852→		buckets[(c-start)/step]++
   853→		if buckets[(c-start)/step] > maxCount {
   854→			maxCount = buckets[(c-start)/step]
   855→		}
   856→	}
   857→	avg := sum / len(datas)
   858→	fmt.Printf("%s (min/avg/max): %d/%d/%d\n", dataType, datas[0], avg, datas[len(datas)-1])
   859→	maxLeftLen := strconv.Itoa(len(fmt.Sprintf("%d", end)))
   860→	maxRightLen := strconv.Itoa(len(fmt.Sprintf("%d", end+step)))
   861→	maxCountLen := strconv.Itoa(len(fmt.Sprintf("%d", maxCount)))
   862→	for bucket, count := range buckets {
   863→		percentage := 100.0 * count / total
   864→		fmt.Printf("[%"+maxLeftLen+"d, %"+maxRightLen+"d]: %"+maxCountLen+"d %s\n", bucket*step+start+1, (bucket+1)*step+start, count, strings.Repeat("#", percentage))
   865→	}
   866→	fmt.Println()
   867→}
   868→
   869→func generateBucket(min, max int) (start, end, step int) {
   870→	s := (max - min) / 10
   871→
   872→	step = 10
   873→	for step < s && step <= 10000 {
   874→		step *= 10
   875→	}
   876→
   877→	start = min - min%step
   878→	end = max - max%step + step
   879→
   880→	return
   881→}
