   185→func (b *writeBenchmark) ingestScrapesShard(lbls []labels.Labels, scrapeCount int, baset int64) (uint64, error) {
   186→	ts := baset
   187→
   188→	type sample struct {
   189→		labels labels.Labels
   190→		value  int64
   191→		ref    *storage.SeriesRef
   192→	}
   193→
   194→	scrape := make([]*sample, 0, len(lbls))
   195→
   196→	for _, m := range lbls {
   197→		scrape = append(scrape, &sample{
   198→			labels: m,
   199→			value:  123456789,
   200→		})
   201→	}
   202→	total := uint64(0)
   203→
   204→	for i := 0; i < scrapeCount; i++ {
   205→		app := b.storage.Appender(context.TODO())
   206→		ts += timeDelta
   207→
   208→		for _, s := range scrape {
   209→			s.value += 1000
   210→
   211→			var ref storage.SeriesRef
   212→			if s.ref != nil {
   213→				ref = *s.ref
   214→			}
   215→
   216→			ref, err := app.Append(ref, s.labels, ts, float64(s.value))
   217→			if err != nil {
   218→				panic(err)
   219→			}
   220→
   221→			if s.ref == nil {
   222→				s.ref = &ref
   223→			}
   224→			total++
   225→		}
   226→		if err := app.Commit(); err != nil {
   227→			return total, err
   228→		}
   229→	}
   230→	return total, nil
   231→}
