   709→type SeriesSetFormatter func(series storage.SeriesSet) error
   710→
   711→func dumpSamples(ctx context.Context, path string, mint, maxt int64, match []string, formatter SeriesSetFormatter) (err error) {
   712→	db, err := tsdb.OpenDBReadOnly(path, nil)
   713→	if err != nil {
   714→		return err
   715→	}
   716→	defer func() {
   717→		err = tsdb_errors.NewMulti(err, db.Close()).Err()
   718→	}()
   719→	q, err := db.Querier(mint, maxt)
   720→	if err != nil {
   721→		return err
   722→	}
   723→	defer q.Close()
   724→
   725→	matcherSets, err := parser.ParseMetricSelectors(match)
   726→	if err != nil {
   727→		return err
   728→	}
   729→
   730→	var ss storage.SeriesSet
   731→	if len(matcherSets) > 1 {
   732→		var sets []storage.SeriesSet
   733→		for _, mset := range matcherSets {
   734→			sets = append(sets, q.Select(ctx, true, nil, mset...))
   735→		}
   736→		ss = storage.NewMergeSeriesSet(sets, storage.ChainedSeriesMerge)
   737→	} else {
   738→		ss = q.Select(ctx, false, nil, matcherSets[0]...)
   739→	}
   740→
   741→	err = formatter(ss)
   742→	if err != nil {
   743→		return err
   744→	}
   745→
   746→	if ws := ss.Warnings(); len(ws) > 0 {
   747→		return tsdb_errors.NewMulti(ws.AsErrors()...).Err()
   748→	}
   749→
   750→	if ss.Err() != nil {
   751→		return ss.Err()
   752→	}
   753→	return nil
   754→}
   755→
   756→func formatSeriesSet(ss storage.SeriesSet) error {
   757→	for ss.Next() {
   758→		series := ss.At()
   759→		lbs := series.Labels()
   760→		it := series.Iterator(nil)
   761→		for it.Next() == chunkenc.ValFloat {
   762→			ts, val := it.At()
   763→			fmt.Printf("%s %g %d\n", lbs, val, ts)
   764→		}
   765→		for it.Next() == chunkenc.ValFloatHistogram {
   766→			ts, fh := it.AtFloatHistogram(nil)
   767→			fmt.Printf("%s %s %d\n", lbs, fh.String(), ts)
   768→		}
   769→		for it.Next() == chunkenc.ValHistogram {
   770→			ts, h := it.AtHistogram(nil)
   771→			fmt.Printf("%s %s %d\n", lbs, h.String(), ts)
   772→		}
   773→		if it.Err() != nil {
   774→			return ss.Err()
   775→		}
   776→	}
   777→	return nil
   778→}
   779→
   780→// CondensedString is labels.Labels.String() without spaces after the commas.
   781→func CondensedString(ls labels.Labels) string {
   782→	var b bytes.Buffer
   783→
   784→	b.WriteByte('{')
   785→	i := 0
   786→	ls.Range(func(l labels.Label) {
   787→		if i > 0 {
   788→			b.WriteByte(',')
   789→		}
   790→		b.WriteString(l.Name)
   791→		b.WriteByte('=')
   792→		b.WriteString(strconv.Quote(l.Value))
   793→		i++
   794→	})
   795→	b.WriteByte('}')
   796→	return b.String()
   797→}
   798→
   799→func formatSeriesSetOpenMetrics(ss storage.SeriesSet) error {
   800→	for ss.Next() {
   801→		series := ss.At()
   802→		lbs := series.Labels()
   803→		metricName := lbs.Get(labels.MetricName)
   804→		lbs = lbs.DropMetricName()
   805→		it := series.Iterator(nil)
   806→		for it.Next() == chunkenc.ValFloat {
   807→			ts, val := it.At()
   808→			fmt.Printf("%s%s %g %.3f\n", metricName, CondensedString(lbs), val, float64(ts)/1000)
   809→		}
   810→		if it.Err() != nil {
   811→			return ss.Err()
   812→		}
   813→	}
   814→	fmt.Println("# EOF")
   815→	return nil
   816→}
   817→
   818→func checkErr(err error) int {
   819→	if err != nil {
   820→		fmt.Fprintln(os.Stderr, err)
   821→		return 1
   822→	}
   823→	return 0
   824→}
   825→
   826→func backfillOpenMetrics(path, outputDir string, humanReadable, quiet bool, maxBlockDuration time.Duration) int {
   827→	inputFile, err := fileutil.OpenMmapFile(path)
   828→	if err != nil {
   829→		return checkErr(err)
   830→	}
   831→	defer inputFile.Close()
   832→
   833→	if err := os.MkdirAll(outputDir, 0o777); err != nil {
   834→		return checkErr(fmt.Errorf("create output dir: %w", err))
   835→	}
   836→
   837→	return checkErr(backfill(5000, inputFile.Bytes(), outputDir, humanReadable, quiet, maxBlockDuration))
   838→}
   839→
   840→func displayHistogram(dataType string, datas []int, total int) {
   841→	if len(datas) == 0 {
   842→		fmt.Printf("%s: N/A\n\n", dataType)
   843→		return
   844→	}
   845→	slices.Sort(datas)
   846→	start, end, step := generateBucket(datas[0], datas[len(datas)-1])
   847→	sum := 0
   848→	buckets := make([]int, (end-start)/step+1)
   849→	maxCount := 0
   850→	for _, c := range datas {
   851→		sum += c
   852→		buckets[(c-start)/step]++
   853→		if buckets[(c-start)/step] > maxCount {
   854→			maxCount = buckets[(c-start)/step]
   855→		}
   856→	}
   857→	avg := sum / len(datas)
   858→	fmt.Printf("%s (min/avg/max): %d/%d/%d\n", dataType, datas[0], avg, datas[len(datas)-1])
   859→	maxLeftLen := strconv.Itoa(len(fmt.Sprintf("%d", end)))
   860→	maxRightLen := strconv.Itoa(len(fmt.Sprintf("%d", end+step)))
   861→	maxCountLen := strconv.Itoa(len(fmt.Sprintf("%d", maxCount)))
   862→	for bucket, count := range buckets {
   863→		percentage := 100.0 * count / total
   864→		fmt.Printf("[%"+maxLeftLen+"d, %"+maxRightLen+"d]: %"+maxCountLen+"d %s\n", bucket*step+start+1, (bucket+1)*step+start, count, strings.Repeat("#", percentage))
   865→	}
   866→	fmt.Println()
   867→}
   868→
   869→func generateBucket(min, max int) (start, end, step int) {
   870→	s := (max - min) / 10
   871→
   872→	step = 10
   873→	for step < s && step <= 10000 {
   874→		step *= 10
   875→	}
   876→
   877→	start = min - min%step
   878→	end = max - max%step + step
   879→
   880→	return
   881→}
